var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"이 방송은 실제 상황입니다.","JPN":"お知らせします。","ENG":"This is not a drill.","TWN":"本次廣播的情況是全部屬實。"},"stage":{"bg":"HARMONY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"현재, 수도 상공에 다수의 미인가 함선이 출몰하였습니다.","JPN":"現在、首都の上空に多数の未認可艦船が出現しました。","ENG":"Currently, multiple unidentified ships have appeared in the capital's airspace.","TWN":"目前，首都上空出現多個未經許可的艦船。"},"stage":{"bg":"HARMONY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"시민 여러분은 군 • 경의 지시에 따라 침착하게 지정된 대피소로 대피해 주시기 바라며…","JPN":"市民の皆さんは軍・警察の指示に従い、落ち着いて指定された避難所まで避難してください……","ENG":"Citizens are advised to evacuate in a composed manner to the assigned shelters in accordance with military and police directives.","TWN":"請各位市民按照軍警的指示，前往指定避難所……"},"stage":{"bg":"HARMONY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그래서…. 저 괴물이 수도에 오게 만들었단 말인가?","JPN":"それで……あの化け物を首都に来るように仕向けたと？","ENG":"So... You made that monster head toward the capital?","TWN":"所以說……你讓那怪物來到首都？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하하, 죄송하게 되었군요.","JPN":"はは、申し訳ありません。","ENG":"Haha. Sorry about that.","TWN":"哈哈，非常抱歉。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"하지만 타나베린으로 향한 건 저희 쪽 예상 밖이었습니다.","JPN":"ですが、タナベリンに向かったのは予想外でした。","ENG":"But we didn't expect it to head to Tanaberin.","TWN":"但我們也沒料到她會選擇去達那貝林。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NAME","text":{"KOREA":"저희도 신뢰 관계를 유지하기 위해 최선을 다했다는 사실은 알아 주세요.","JPN":"私たちも信頼関係を維持するために最善を尽くしたということだけはわかってください。","ENG":"Please note that we did our best to maintain our truce.","TWN":"希望您能明白，我們已經為彼此的信任關係盡了全力。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"국장님, 수상관저에서 들어온 급보입니다.","JPN":"局長、首相官邸からの急報です。","ENG":"Sir, it's an urgent report from the Prime Minister.","TWN":"局長，來自首長官邸的緊急消息。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"뭐지? 보고하도록.","JPN":"何だ？　報告しろ。","ENG":"What? Let's hear it.","TWN":"什麼？報告吧。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로 네퀴티아가 정부에 보낸 제안이라고 합니다. 보십시오.","JPN":"マエストロ・ネキティアから政府に送った提案とのことです。ご覧ください。","ENG":"It is a proposition to our government from Maestra Nequitia. Here you go, sir.","TWN":"這是指揮家·莉奎蒂亞向政府提出的提議。請過目。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"정기적으로, 국민의 10%를 제공하라…?","JPN":"定期的に、国民の10％を提供しろだと……？","ENG":"She wants us to provide her with 10% of the population on a regular basis...?","TWN":"定期獻出10%的國民……？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"연령대와 성별의 비율까지…… 이건 제안이 아니라 우리 정부에 대한 모욕이지 않나!","JPN":"年齢層と性別の比率まで……これは提案ではなく、我々政府に対する侮辱ではないか！","ENG":"She even wrote the age and gender ratio... This isn't a proposition, it's a mockery of our government!","TWN":"還要求特定年齡段和性別比例……這不是提議，這是對我們政府的侮辱！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"하, 하지만…….","JPN":"で、ですが……","ENG":"H-however...","TWN":"可…可是……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"예, 각하. 방금 제안 내용을 확인했습니다.","JPN":"はい、閣下。ただいま、提案の内容を確認しました。","ENG":"Yes, Prime Minster. I just now confirmed the proposition.","TWN":"是，總理。剛看到提議內容。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>좋아. 그렇다면 설명할 수고는 덜었군.</color>","JPN":"<color=#ffd34c>よろしい。なら、説明する必要はないな。</color>","ENG":"<color=#ffd34c>Good. That saves me the trouble of explaining it to you.</color>","TWN":"<color=#ffd34c>很好。那我就長話短說。</color>"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>계엄령은 이미 내렸다네. 보안국이 바쁘게 움직여 줘야겠어.</color>","JPN":"<color=#ffd34c>すでに戒厳令を敷いている。保安局には急いで動いてもらおう。</color>","ENG":"<color=#ffd34c>I've already declared martial law. I expect the National Security to be swift.</color>","TWN":"<color=#ffd34c>現在已經發布戒嚴令，安全局要抓緊時間採取行動。</color>"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하, 지금 저 제안을 받아들이셨다는 겁니까? 저에게 한마디 언질이라도 주셨어야죠!","JPN":"閣下、あの提案を受け入れたとおっしゃっているのですか？　私に意見を求めることもなく！","ENG":"Sir, have you already accepted this proposition? You should have told me in advance!","TWN":"總理，難道您已經接受了她的提議嗎？至少應該和我說一聲！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};